import numpy as np
from qiskit.quantum_info import Statevector, Pauli
observed = Statevector.from_label('0').evolve(Pauli('X')).data
s = 1 / np.sqrt(2)
cands = {"A": np.array([0, 1]), "B": np.array([1, 0]), "C": np.array([s, s]), "D": np.array([0, 1j])}
evidence = {}
proven = []
for k, v in cands.items():
    m = bool(np.allclose(observed, v))
    evidence[k] = f"|0>.evolve(X) = {np.round(observed, 4).tolist()}; option {k} claims {np.round(v, 4).tolist()} -> match={m}"
    if m:
        proven.append(k)
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"data": [str(x) for x in observed]}})
